VALUES
  ('elementary-f29af906-moex-00778', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關行政程序法規定之期日與期間之計算方式，下列敘述何者錯誤？', '["期間之末日為星期六者，以其次星期一為期間末日", "期間以時計算者，即時起算", "期間之末日為星期日、國定假日或其他休息日者，以該日之次日為期間之末日", "期間以日、星期、月或年計算者，其始日計算在內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00779', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地徵收條例規定，被徵收之土地，未依核准徵收原定興辦事業使用者，原土地所有權人得向下列何 者申請收回原被徵收之土地？', '["鄉（鎮）公所", "直轄市或縣（市）主管機關", "內政部地政司", "需地機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00780', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '行政程序法第46條規定：「當事人或利害關係人得向行政機關申請閱覽、抄寫、複印或攝影有關資料或 卷宗。但以主張或維護其法律上之利益有必要者為限。行政機關對前項之申請，除有下列情形之一者外， 不得拒絕：……。」有關前開規定之除外情形，下列何者不屬之？', '["行政決定前之擬稿或其他準備作業文件", "涉及國防及一般公務機密，依法規規定有保密之必要者", "涉及個人隱私、職業秘密、營業秘密，依法規規定有保密之必要者", "涉及軍事及外交事務而無保密之必要者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00781', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '我國憲法第23條規定：「以上各條列舉之自由權利，除為防止妨害他人自由、避免緊急危難、維持社會', '["比例原則", "法律保留原則", "誠實信用原則", "信賴保護原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00782', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '1989 年國小老師李幸長發起「無殼蝸牛運動」，夜宿臺北市忠孝東路，抗議政府漠視人民的居住權益。 後來，無住屋運動轉型為「崔媽媽基金會」，透過協助弱勢族群解決租屋問題，落實「居者適其屋」的 理念。關於「無殼蝸牛運動」發展到「崔媽媽基金會」之成立，下列敘述何者正確？', '["由非營利組織轉型為營利組織", "原強調利他主義後轉為主張利己導向", "原以公益為使命後轉為重視成本效益", "從倡議的社會運動轉為成立服務性的社團"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00783', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '近年來雙薪家庭比例上升，由於父母忙於工作，因此托兒所、安親班等機構成為安置孩童的重要處所。 根據統計，臺灣目前有政府立案的各種安親班、補習班、才藝班數量遠遠超過全臺超商數量。此現象說 明隨著社會變遷，家庭的何種功能正在轉變？', '["生育功能", "經濟功能", "社會化功能", "傳遞社會地位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00784', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '所謂「友善職場」，就是無歧視、重平等的職場。在職場中，勞工與雇主彼此尊重、合作，共同打造一 個性別平權的工作環境。下列何種作法，最有助於促進「友善職場」？', '["開放同志勞工因伴侶生病時可請家庭照顧假", "營造玻璃天花板環境以便落實性別實質平等", "健全性別職業隔離制度以保障女性就業機會", "降低女性勞動參與率以避免蠟燭兩頭燒現象"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00785', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '有關法律分類的敘述，下列何者正確？', '["民法：不成文法、私法、普通法、實體法", "民事訴訟法：成文法、私法、特別法、程序法", "刑事訴訟法：成文法、公法、普通法、程序法", "勞動基準法：不成文法、社會法、特別法、實體法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00786', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '隨著高齡化社會的來臨，國際移工的身影已深入臺灣家庭，然而媒體總以「口音怪異、膚色黝黑、吵雜 或是忠誠度不足、常常逃跑」來形容移工的樣貌。由此可知，媒體主要是透過下列何種方式來影響閱聽 人的認知？', '["總白癡化", "置入性行銷", "暴力行為的複製", "形塑刻板印象與歧視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00787', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '根據公民投票法之規定：「當國家遭受外力威脅，致國家主權有改變之虞，甲得經行政院院會之決議， 就攸關國家安全事項，交付公民投票。」關於甲的法定職權，下列敘述何者正確？', '["可向立法院提出覆議", "享有被動解散國會權", "可以提出憲法修正案", "掌理公務員懲戒事宜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
